if __name__ == '__main__':
    print('H shape:', H.shape)
    print('col weight min/max:', int(H.sum(axis=0).min()), int(H.sum(axis=0).max()))
    print('row weight min/max:', int(H.sum(axis=1).min()), int(H.sum(axis=1).max()))
    assert H.shape == (500, 1000)
    assert np.all(H.sum(axis=0) == 3)
    assert np.all(H.sum(axis=1) == 6)
    print('OK ✅')
